    stack: list = [(spec["tree"], top)];
    while len(stack) > 0 {
        item = stack.pop();
        d = item[0];
        parent = item[1];
        for (fname, size) in d["files"] { parent ++> File(name=str(fname), size=int(size)); }
        for sub in d["dirs"] {
            child = Folder(name=str(sub["name"]));
            parent ++> child;
            stack.append((sub, child));
        }
    }
    return (top spawn SizeSum()).total;
}

