def orphan_pages(spec: dict) -> list:
    """Alphabetical list of pages unreachable from the start page."""
    adj = {p: [] for p in spec["pages"]}
    for src, dst in spec["links"]:
        if src in adj and dst in adj:
            adj[src].append(dst)
